import{_ as e}from"./plugin-vue_export-helper-c27b6911.js";import{o as a,c as i,e as r}from"./app-be253e4c.js";const d={},h=r('<h1 id="模板方法模式" tabindex="-1"><a class="header-anchor" href="#模板方法模式" aria-hidden="true">#</a> 模板方法模式</h1><p>模板方法模式<code>Template Method Pattern</code> 定义了如何执行某些算法的框架，一个抽象类公开定义了执行它的方法的方式或模板，其子类可以按需要重写方法实现，也可以调用将以抽象类中定义的方式进行，这种类型的设计模式属于行为型模式。</p><h2 id="基本介绍" tabindex="-1"><a class="header-anchor" href="#基本介绍" aria-hidden="true">#</a> 基本介绍</h2><p>模板方法模式是一种行为设计模式，用于定义操作中算法的程序框架，从而将某些步骤推迟到子类中，其可以重新定义算法的某些步骤，而无需更改算法的结构。</p><h3 id="优点" tabindex="-1"><a class="header-anchor" href="#优点" aria-hidden="true">#</a> 优点</h3><ul><li>封装不变部分，扩展可变部分，提高了拓展性。</li><li>提取公共代码，便于维护，提高代码复用性。</li><li>行为由父类控制，子类实现，实现了反向控制 ，符合开闭原则。</li></ul><h3 id="缺点" tabindex="-1"><a class="header-anchor" href="#缺点" aria-hidden="true">#</a> 缺点</h3><ul><li>每一个不同的实现都需要一个子类来实现，导致类的个数增加，使得系统更加庞大。</li></ul><h3 id="适用环境" tabindex="-1"><a class="header-anchor" href="#适用环境" aria-hidden="true">#</a> 适用环境</h3><ul><li>有多个子类共有的方法，且逻辑相同。</li><li>重要的、复杂的方法，可以考虑作为模板方法。</li></ul><h2 id="代码实现" tabindex="-1"><a class="header-anchor" href="#代码实现" aria-hidden="true">#</a> 代码实现</h2>',11),t=[h];function l(n,c){return a(),i("div",null,t)}const u=e(d,[["render",l],["__file","template-method-mode.html.vue"]]);export{u as default};
